function isEmpty(source) {
    // Checks for null, undefined, not an array, or empty array
    return !Array.isArray(source) || source.length === 0;
}

logger.error("Source tags: " + JSON.stringify(source));
var resultArray = [];
if(!isEmpty(source)){
logger.error("tagsarray length : "+source.length);
for(var i = 0; i < source.length; i++){
	var sourceTagId = source[i]._refResourceId;
	logger.error("sourceTagId ref: "+sourceTagId);

	try {

		var tagsResponse = openidm.query(
			"managed/alpha_kyid_tag",{
				 "_queryFilter": '_id eq "' + sourceTagId + '"'
			},
			["name"]
		);
		logger.error("Tags Response: " + JSON.stringify(tagsResponse));

		if (tagsResponse.result && tagsResponse.result.length == 1) {

			var tagId = tagsResponse.result[0].name;
			logger.error("tagId in response : "+tagId);
			resultArray.push(tagId);

		} else {
			logger.error("Exception occurred during widget to tag link " );
		}
	} catch (e) {
		logger.error("Exception occurred: " + e);  
	}

}
var resultString = resultArray.join(',');
logger.error("Result Array : " + resultString);
resultString;
}else{
	null;
}
